 1	import type { FC } from 'react';
 2	
 3	import { ConsoleTimestamp } from '@components/ConsoleTimestamp/ConsoleTimestamp';
 4	import SectionHeading from '@components/headers/SectionHeading';
 5	import type { IoK8sApiCoreV1PersistentVolumeClaim } from '@kubev2v/types';
 6	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 8	import { EMPTY_MSG } from '@utils/constants';
 9	import { PersistentVolumeClaimModelGroupVersionKind } from '@utils/crds/common/models';
10	import { getName, getNamespace, getUID } from '@utils/crds/common/selectors';
11	import { isEmpty } from '@utils/helpers';
12	import { useForkliftTranslation } from '@utils/i18n';
13	
14	type MigrationPVCsTableProps = {
15	  pvcs: IoK8sApiCoreV1PersistentVolumeClaim[];
16	};
17	
18	const MigrationPVCsTable: FC<MigrationPVCsTableProps> = ({ pvcs }) => {
19	  const { t } = useForkliftTranslation();
20	
21	  if (isEmpty(pvcs)) {
22	    return null;
23	  }
24	  return (
25	    <>
26	      <SectionHeading
27	        text={t('PersistentVolumeClaims')}
28	        textComponent="h3"
29	        className="migration-status-expanded-page__resource-list-header"
30	      />
31	      <Table>
32	        <Thead>
33	          <Tr>
34	            <Th width={40}>{t('Name')}</Th>
35	            <Th width={20}>{t('Description')}</Th>
36	            <Th>{t('Created at')}</Th>
37	          </Tr>
38	        </Thead>
39	        <Tbody>
40	          {(pvcs || []).map((pvc) => (
41	            <Tr key={getUID(pvc)}>
42	              <Td width={40}>
43	                <ResourceLink
44	                  groupVersionKind={PersistentVolumeClaimModelGroupVersionKind}
45	                  name={getName(pvc)}
46	                  namespace={getNamespace(pvc)}
47	                />
48	              </Td>
49	              <Td width={20}>{pvc?.status?.phase ?? EMPTY_MSG}</Td>
50	              <Td>
51	                <ConsoleTimestamp
52	                  timestamp={pvc?.metadata?.creationTimestamp}
53	                  showGlobalIcon={false}
54	                />
55	              </Td>
56	            </Tr>
57	          ))}
58	        </Tbody>
59	      </Table>
60	    </>
61	  );
62	};
63	
64	export default MigrationPVCsTable;

